                  ConstantInt *CI = cast<ConstantInt>(CA->getOperand(i));
                  if (CI->isZero())
                    TrueValCouldBeZero = true;
                } else {
                  TrueValCouldBeZero = true; // unknown value could be zero
                }
              }
            } else if (isa<ConstantInt>(TrueVal)) {
              TrueValCouldBeZero = cast<ConstantInt>(TrueVal)->isZero();
            } else {
              TrueValCouldBeZero = true; // unknown value could be zero
            }

            // Check if false value could be zero  
