              ConstantAggregate *CA = cast<ConstantAggregate>(FalseVal);
              for (unsigned i = 0; i < CA->getNumOperands(); ++i) {
                if (isa<ConstantInt>(CA->getOperand(i))) {
                  ConstantInt *CI = cast<ConstantInt>(CA->getOperand(i));
                  if (CI->isZero())
                    FalseValCouldBeZero = true;
                } else {
                  FalseValCouldBeZero = true; // unknown value could be zero
                }
              }
            } else if (isa<ConstantInt>(FalseVal)) {
              FalseValCouldBeZero = cast<ConstantInt>(FalseVal)->isZero();
            } else {
              FalseValCouldBeZero = true; // unknown value could be zero
            }

