            // because it would incorrectly handle poison in vector lanes
            if (TrueValCouldBeZero || FalseValCouldBeZero) {
              // Don't perform optimizations that would incorrectly handle
              // mixed poison/non-poison vector lanes
              return nullptr;
            }
          }
        }
      }
    }
  }

  return nullptr;
}
